<!-- Tombol Panduan (Tour) -->
<button onclick="mulaiTour()" title="Mulai Panduan" style="margin-right: 15px; background: #eff6ff; border: 1px solid #bfdbfe; color: #1e3a8a; border-radius: 50%; width: 40px; height: 40px; display: flex; align-items: center; justify-content: center; cursor: pointer; transition: all 0.2s; box-shadow: 0 1px 2px rgba(0,0,0,0.05);" onmouseover="this.style.background='#dbeafe'; this.style.transform='scale(1.05)';" onmouseout="this.style.background='#eff6ff'; this.style.transform='scale(1)';">
    <i class="ph-bold ph-question" style="font-size: 22px;"></i>
</button>
